local function init()
    local config = FileUtil.getConfigFromCsv("setting/CustomShopBlock.csv")
    for _, item in pairs(config) do
        CustomShopBlock.Settings[item.Id] = {
            Id = tonumber(item.Id),
            BlockId = tonumber(item.BlockId),
            DressBlockId = tonumber(item.DressBlockId),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action
        }
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopFootprint.csv")
    for _, item in pairs(config) do
        CustomShopFootprint.Settings[item.Id] = {
            Id = tonumber(item.Id),
            FootprintId = tonumber(item.FootprintId),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action
        }
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopPet.csv")
    for _, item in pairs(config) do
        local offset = StringUtil.split(item.offset, ",")
        local uiOffset = StringUtil.split(item.uiOffset, ",")
        if #offset == 3 and #uiOffset == 2 then
            CustomShopPet.Settings[item.Id] = {
                Id = tonumber(item.Id),
                ActorName = tostring(item.ActorName),
                xOffset = tonumber(offset[1]),
                yOffset = tonumber(offset[2]),
                zOffset = tonumber(offset[3]),
                uiXOffset = tonumber(uiOffset[1]),
                uiYOffset = tonumber(uiOffset[2]),
                uiPlayerSkill = tostring(item.uiPlayerSkill or "run"),
                uiSkillName = tostring(item.uiSkillName),
                pendant = tostring(item.pendant),
                tauntTime = tonumber(item.tauntTime or 5000),
                scale = tonumber(item.scale or 1),
            }
        end
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopAction.csv")
    for _, item in pairs(config) do
        CustomShopAction.Settings[item.Id] = {
            Id = tonumber(item.Id),
            ActionId = tonumber(item.ActionId),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action
        }
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopEffectArrow.csv")
    for _, item in pairs(config) do
        CustomShopEffectArrow.Settings[item.Id] = {
            Id = tonumber(item.Id),
            EffectArrowId = tonumber(item.EffectArrowId),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action
        }
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopSwordLight.csv")
    for _, item in pairs(config) do
        local OffsetParams = StringUtil.split(item.OffsetParams or "0#0#0", "#")
        local ScaleParams = StringUtil.split(item.ScaleParams or "0#0#0", "#")
        CustomShopSwordLight.Settings[item.Id] = {
            Id = tonumber(item.Id),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action,
            SceneAction = item.SceneAction or item.Action,
            IdleTime = tonumber(item.IdleTime or 700),
            Effect = item.Effect,
            Offset = VectorUtil.newVector3(OffsetParams[1], OffsetParams[2], OffsetParams[3]),
            Scale = VectorUtil.newVector3(ScaleParams[1], ScaleParams[2], ScaleParams[3])
        }
    end

    config = FileUtil.getConfigFromCsv("setting/CustomShopCloth.csv")
    for _, item in pairs(config) do
        CustomShopCloth.Settings[item.Id] = {
            Id = tonumber(item.Id),
            PartName = item.PartName,
            MeshName = item.MeshName,
            Action = item.Action or "idle"
        }
    end

end

